import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "../../api/axios";

const STATUS_STYLES = {
  scheduled: { bg: "rgba(12, 58, 87, 0.08)", color: "#0C3A57", label: "Scheduled" },
  completed: { bg: "rgba(141, 187, 1, 0.12)", color: "#8DBB01", label: "Completed" },
  cancelled: { bg: "rgba(186, 94, 94, 0.12)", color: "#ba5e5e", label: "Cancelled" },
};

const formatSlot = (time) => {
  if (!time) return "—";
  const [hours, minutes] = time.split(":").map(Number);
  const suffix = hours >= 12 ? "PM" : "AM";
  const hour12 = hours % 12 || 12;
  return `${hour12}:${String(minutes).padStart(2, "0")} ${suffix}`;
};

export default function MyAppointments() {
  const [appointments, setAppointments] = useState([]);
  const [deleting, setDeleting] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    api
      .get("/customer/appointments/my")
      .then((res) => setAppointments(res.data))
      .catch((err) => alert(err.response?.data?.message || "Failed to load"));
  }, []);

  const stats = useMemo(() => {
    const total = appointments.length;
    const scheduled = appointments.filter((a) => a.status === "scheduled").length;
    const completed = appointments.filter((a) => a.status === "completed").length;
    return { total, scheduled, completed };
  }, [appointments]);

  const deleteAppointment = async (id) => {
    if (!window.confirm("Are you sure you want to cancel this appointment?")) return;

    setDeleting(id);
    try {
      await api.delete(`/customer/appointments/${id}`);
      setAppointments((current) => current.filter((appointment) => appointment._id !== id));
    } catch (err) {
      const errorMsg = err.response?.data?.message || err.message || "Failed to cancel appointment";
      alert(errorMsg);
    } finally {
      setDeleting(null);
    }
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">My Appointments</div>
          <div className="pageSub">Track your bookings, upcoming showroom visits, and assigned staff details.</div>
        </div>
        <button onClick={() => navigate("/book-appointment")} className="btn btnPrimary">
          Book Appointment
        </button>
      </div>

      <div className="kpiGrid">
        <MetricCard label="Total" value={stats.total} sub="All bookings" />
        <MetricCard label="Scheduled" value={stats.scheduled} sub="Upcoming visits" />
        <MetricCard label="Completed" value={stats.completed} sub="Finished appointments" />
        <MetricCard label="Next Step" value={stats.scheduled ? "Ready" : "Plan"} sub="Your current status" />
      </div>

      {appointments.length === 0 ? (
        <div className="card cardPad" style={{ maxWidth: "760px", margin: "32px auto", textAlign: "center", color: "var(--text-muted)" }}>
          <div style={{ fontSize: "18px", fontWeight: 700, color: "var(--navy)", marginBottom: "10px" }}>No appointments yet</div>
          <div style={{ marginBottom: "18px" }}>Book your first appointment to schedule a viewing or test drive.</div>
          <button onClick={() => navigate("/book-appointment")} className="btn btnPrimary">
            Book Your First Appointment
          </button>
        </div>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))", gap: "18px" }}>
          {appointments.map((appointment) => {
            const statusStyle = STATUS_STYLES[appointment.status] || STATUS_STYLES.scheduled;
            return (
              <div key={appointment._id} className="card cardPad" style={{ display: "grid", gap: "16px" }}>
                <div style={{ display: "flex", justifyContent: "space-between", gap: "14px", alignItems: "flex-start" }}>
                  <div style={{ display: "grid", gap: "8px" }}>
                    <div style={{ fontSize: "22px", fontWeight: 800, color: "var(--navy)", lineHeight: 1.2 }}>
                      {appointment.vehicle?.brand} {appointment.vehicle?.model || appointment.vehicle?.type || ""}
                    </div>
                    <span
                      style={{
                        width: "fit-content",
                        padding: "6px 10px",
                        borderRadius: "999px",
                        background: statusStyle.bg,
                        color: statusStyle.color,
                        fontSize: "11px",
                        fontWeight: 700,
                        textTransform: "uppercase",
                        letterSpacing: "0.08em",
                      }}
                    >
                      {statusStyle.label}
                    </span>
                  </div>
                  <div style={{ color: "var(--text-muted)", fontSize: "13px", fontWeight: 600 }}>{appointment.vehicle?.year || ""}</div>
                </div>

                <div
                  style={{
                    display: "grid",
                    gap: "10px",
                    padding: "14px",
                    borderRadius: "16px",
                    background: "rgba(236, 236, 236, 0.42)",
                    border: "1px solid rgba(12, 58, 87, 0.06)",
                  }}
                >
                  <InfoRow
                    label="Date"
                    value={new Date(appointment.date).toLocaleDateString("en-US", {
                      weekday: "short",
                      month: "short",
                      day: "numeric",
                      year: "numeric",
                    })}
                  />
                  <InfoRow label="Session" value={formatSlot(appointment.time)} />
                  <InfoRow label="Staff" value={appointment.staffMember?.name || "To be assigned"} />
                </div>

                {appointment.staffMember?.email ? (
                  <div style={{ color: "var(--text-secondary)", fontSize: "14px" }}>
                    Contact: <strong style={{ color: "var(--navy)" }}>{appointment.staffMember.email}</strong>
                  </div>
                ) : null}

                <div style={{ display: "flex", gap: "10px", flexWrap: "wrap" }}>
                  <button
                    onClick={() => navigate(`/edit-my-appointment/${appointment._id}`)}
                    className="btn"
                    disabled={appointment.status !== "scheduled"}
                    style={{ flex: 1, opacity: appointment.status !== "scheduled" ? 0.5 : 1 }}
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => deleteAppointment(appointment._id)}
                    className="btn"
                    disabled={appointment.status !== "scheduled" || deleting === appointment._id}
                    style={{
                      flex: 1,
                      opacity: appointment.status !== "scheduled" ? 0.5 : 1,
                      color: "var(--danger)",
                      borderColor: "rgba(186, 94, 94, 0.25)",
                    }}
                  >
                    {deleting === appointment._id ? "Cancelling..." : "Cancel"}
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

function MetricCard({ label, value, sub }) {
  return (
    <div className="kpiCard">
      <div className="kpiLabel">{label}</div>
      <div className="kpiValue">{value}</div>
      <div className="kpiSub">{sub}</div>
    </div>
  );
}

function InfoRow({ label, value }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", gap: "16px", alignItems: "center" }}>
      <span style={{ color: "var(--text-muted)", fontSize: "12px", fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.08em" }}>
        {label}
      </span>
      <span style={{ color: "var(--navy)", fontSize: "14px", fontWeight: 700, textAlign: "right" }}>{value}</span>
    </div>
  );
}
